const inputData = $input.first().json; 
const texto_bruto = inputData.output || inputData.text || "";

const extraerTexto = (campo, fallback) => {
    const regex = new RegExp(`${campo}[:\\s]+([^\\n]+)`, 'i');
    const match = texto_bruto.match(regex);
    return match ? match[1].trim() : fallback;
};

// Extrae solo el PRIMER número de la lista para BigQuery
const extraerPrimerNumero = (campo, fallback) => {
    const texto = extraerTexto(campo, "");
    if (!texto) return fallback;
    const primerNumero = texto.split(',')[0].trim(); 
    return parseFloat(primerNumero.replace(',', '.')) || fallback;
};

const reporte_limpio = texto_bruto.replace(/\[MOSTRAR_GRAFICO\][\s\S]*/i, "").trim();

return [{
    json: {
        // --- DATOS PARA BIGQUERY (datos_sectoriales) ---
        timestamp: new Date().toISOString(),
        session_id: inputData.session_id || `energia-${Date.now()}`,
        sector: "ENERGIA", 

        tipo_energia: extraerTexto("tipo_energia", "Híbrida"),
        ubicacion: extraerTexto("ubicacion", "S/D"),
        radiacion_solar: extraerPrimerNumero("radiacion_solar", 0),
        velocidad_viento: extraerPrimerNumero("velocidad_viento", 0),
        temperatura_ambiente: extraerPrimerNumero("temperatura_ambiente", 25),
        eficiencia_estimada: extraerPrimerNumero("eficiencia_estimada", 80),
        produccion_kwh: extraerPrimerNumero("produccion_kwh", 0),

        ai_efficiency_analysis: reporte_limpio,

        metadata: JSON.stringify({ 
            status: "success", 
            trigger_input: inputData.query || "Entrada Energía" 
        }),

        // --- DATOS PARA DJANGO Y CHART.JS (Con las listas completas) ---
        output: texto_bruto 
    }
}];
